import React, { useEffect, useState, useRef } from 'react';
import { useParams, Link } from 'react-router-dom';
import { useReactToPrint } from 'react-to-print';
import Layout from '../components/layout/Layout';
import api from '../services/api';
import { formatCurrency, formatDate, numberToWords } from '../utils/helpers';

/* ══════════════════════════════════════════════════════════════════
   INVOICE PRINT COMPONENT
   All styles are inline so they survive print/PDF rendering.
   Font-size is strictly 9pt throughout the table.
══════════════════════════════════════════════════════════════════ */
const InvoicePrint = React.forwardRef(({ invoice, settings }, ref) => {
  const s      = settings || {};
  const intra  = invoice.supplyType !== 'inter';
  const isGST  = invoice.billingType === 'gst';

  /* base cell style — every cell uses this */
  const cell = (extra = {}) => ({
    border: '1px solid #000',
    padding: '4px 5px',
    fontSize: 9,
    fontFamily: 'Arial, Helvetica, sans-serif',
    verticalAlign: 'top',
    lineHeight: '1.35',
    ...extra,
  });

  const hCell = (extra = {}) => cell({ background: '#e8e8e8', fontWeight: 'bold', textAlign: 'center', verticalAlign: 'middle', ...extra });

  /* ── column widths (must sum to 100%) ── */
  /* intra-GST:  SNo | Desc | HSN | Qty | UOM | Rate | Taxable | CGSTr | CGSTa | SGSTr | SGSTa | Total */
  /* inter-GST:  SNo | Desc | HSN | Qty | UOM | Rate | Taxable | IGSTr | IGSTa | Total */
  /* non-GST:    SNo | Desc | HSN | Qty | UOM | Rate | Taxable | Total */
  const cols = isGST
    ? (intra
        ? ['3%','28%','7%','4%','4%','7%','9%','4%','6%','4%','6%','8%']
        : ['3%','34%','7%','4%','4%','8%','10%','4%','7%','9%'])
    : ['4%','40%','8%','5%','5%','10%','14%','14%'];

  return (
    <div ref={ref} style={{ fontFamily: 'Arial, Helvetica, sans-serif', fontSize: 9, color: '#000', background: '#fff', padding: '10px 12px', width: '100%', boxSizing: 'border-box' }}>

      {/* ── HEADER ────────────────────────────────────────────────── */}
      <table style={{ width: '100%', borderCollapse: 'collapse', tableLayout: 'fixed' }}>
        <colgroup><col style={{ width: '62%' }} /><col style={{ width: '38%' }} /></colgroup>
        <tbody>
          <tr>
            <td style={cell({ padding: '8px 10px', verticalAlign: 'middle', borderRight: 'none' })}>
              <div style={{ fontSize: 16, fontWeight: 900, letterSpacing: 0.5 }}>TAX INVOICE</div>
              <div style={{ fontSize: 18, fontWeight: 900, textTransform: 'uppercase', marginTop: 1 }}>{s.shopName}</div>
              <div style={{ fontSize: 9, marginTop: 2, color: '#333' }}>
                {[s.shopAddress, s.shopCity, s.shopState, s.shopPincode].filter(Boolean).join(', ')}
              </div>
              {s.shopPhone && <div style={{ fontSize: 9, marginTop: 1 }}>PHONE: {s.shopPhone}</div>}
              {s.shopGstin && <div style={{ fontSize: 9, marginTop: 3 }}><strong>Gstin Number: {s.shopGstin}</strong></div>}
              <div style={{ fontSize: 8, marginTop: 2, color: '#666', fontStyle: 'italic' }}>
                FORMERLY SWARAJ MAZDA — AUTHORISED SERVICE CENTER &amp; DISTRIBUTORS &amp; DEALERS OF SPARE PARTS
              </div>
            </td>
            <td style={cell({ padding: '8px 10px', verticalAlign: 'top' })}>
              <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 9 }}>
                <tbody>
                  {[
                    ['Invoice Serial Number', invoice.invoiceNumber, true],
                    ['Invoice Date',          formatDate(invoice.invoiceDate), false],
                    ['Place of Supply',       invoice.placeOfSupply || 'CHANDIGARH', false],
                    invoice.vehicleModel   ? ['Model',    invoice.vehicleModel,   false] : null,
                    invoice.vehicleNumber  ? ['Veh. No',  invoice.vehicleNumber,  false] : null,
                    ['Transportation Mode',  'BY HAND', false],
                    ['Payment Status',       (invoice.paymentStatus || '').toUpperCase(), true],
                  ].filter(Boolean).map(([label, val, bold], i) => (
                    <tr key={i}>
                      <td style={{ padding: '2px 0', paddingRight: 8, whiteSpace: 'nowrap', color: '#444', fontSize: 9 }}>{label}</td>
                      <td style={{ padding: '2px 0', fontWeight: bold ? 700 : 400, fontSize: 9 }}>: {val}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
              {s.bankName && (
                <div style={{ marginTop: 6, paddingTop: 5, borderTop: '1px solid #ccc', fontSize: 9 }}>
                  <div><strong>BANK NAME :</strong> {s.bankName}</div>
                  {s.bankAccount && <div><strong>A/C NO :</strong> {s.bankAccount}</div>}
                  {s.bankIfsc    && <div><strong>IFSC CODE :</strong> {s.bankIfsc}</div>}
                </div>
              )}
            </td>
          </tr>
        </tbody>
      </table>

      {/* ── BILLED TO / SHIP TO ───────────────────────────────────── */}
      <table style={{ width: '100%', borderCollapse: 'collapse', tableLayout: 'fixed', marginTop: -1 }}>
        <colgroup><col style={{ width: '50%' }} /><col style={{ width: '50%' }} /></colgroup>
        <tbody>
          <tr>
            {['Details of Receiver (Billed to)', 'Details of Receiver (Ship to)'].map((label, ci) => (
              <td key={ci} style={{ ...cell({ padding: 0, borderLeft: ci === 1 ? 'none' : undefined }), verticalAlign: 'top' }}>
                <div style={{ background: '#e8e8e8', fontWeight: 700, fontSize: 9, padding: '3px 8px', borderBottom: '1px solid #ccc' }}>
                  {label}
                </div>
                <div style={{ padding: '5px 8px', fontSize: 9, lineHeight: 1.6 }}>
                  <div><strong>Name :</strong> {invoice.customerName}</div>
                  {invoice.customerAddress   && <div><strong>Address :</strong> {invoice.customerAddress}</div>}
                  {invoice.customerGstin     && <div><strong>GSTIN Number :</strong> {invoice.customerGstin}</div>}
                  {invoice.customerStateCode && <div><strong>State Code :</strong> {invoice.customerStateCode}</div>}
                  {invoice.customerMobile    && <div><strong>Phone No. :</strong> {invoice.customerMobile}</div>}
                </div>
              </td>
            ))}
          </tr>
        </tbody>
      </table>

      {/* ── ITEMS TABLE ───────────────────────────────────────────── */}
      <table style={{ width: '100%', borderCollapse: 'collapse', tableLayout: 'fixed', marginTop: -1 }}>
        <colgroup>{cols.map((w, i) => <col key={i} style={{ width: w }} />)}</colgroup>
        <thead>
          {/* Row 1: main headers */}
          <tr>
            <th style={hCell()}>S.No</th>
            <th style={hCell({ textAlign: 'left' })}>Description of Goods &amp; Part No</th>
            <th style={hCell()}>HSN / SAC</th>
            <th style={hCell()}>Qty</th>
            <th style={hCell()}>UOM</th>
            <th style={hCell({ textAlign: 'right' })}>Rate</th>
            <th style={hCell({ textAlign: 'right' })}>Taxable Value</th>
            {isGST && intra  && <th style={hCell()} colSpan={2}>CGST</th>}
            {isGST && intra  && <th style={hCell()} colSpan={2}>UTGST</th>}
            {isGST && !intra && <th style={hCell()} colSpan={2}>IGST</th>}
            <th style={hCell({ textAlign: 'right' })}>Total</th>
          </tr>
          {/* Row 2: Rate / Amount sub-headers */}
          {isGST && (
            <tr>
              <th style={hCell()} colSpan={7}></th>
              <th style={hCell()}>Rate</th>
              <th style={hCell({ textAlign: 'right' })}>Amount</th>
              {intra && <><th style={hCell()}>Rate</th><th style={hCell({ textAlign: 'right' })}>Amount</th></>}
              <th style={hCell()}></th>
            </tr>
          )}
        </thead>
        <tbody>
          {invoice.items.map((item, i) => (
            <tr key={i} style={{ background: i % 2 === 1 ? '#fafafa' : '#fff' }}>
              <td style={cell({ textAlign: 'center', borderTop: 'none' })}>{i + 1}</td>
              <td style={cell({ textAlign: 'left', borderTop: 'none', borderLeft: 'none' })}>
                <div style={{ fontWeight: 700, fontSize: 9 }}>{item.productName}</div>
                {item.brandName && item.brandName !== item.productName && (
                  <div style={{ color: '#555', fontSize: 8 }}>{item.brandName}</div>
                )}
                {item.partNumber && (
                  <div style={{ color: '#666', fontSize: 8 }}>PART NO: {item.partNumber}</div>
                )}
              </td>
              <td style={cell({ textAlign: 'center', borderTop: 'none', borderLeft: 'none' })}>{item.hsnCode}</td>
              <td style={cell({ textAlign: 'center', borderTop: 'none', borderLeft: 'none' })}>{item.quantity}</td>
              <td style={cell({ textAlign: 'center', borderTop: 'none', borderLeft: 'none' })}>{item.unit}</td>
              <td style={cell({ textAlign: 'right', borderTop: 'none', borderLeft: 'none', fontFamily: 'Courier New, monospace' })}>{(+item.rate).toFixed(2)}</td>
              <td style={cell({ textAlign: 'right', borderTop: 'none', borderLeft: 'none', fontFamily: 'Courier New, monospace' })}>{(+item.taxableValue).toFixed(2)}</td>
              {isGST && intra && <>
                <td style={cell({ textAlign: 'center', borderTop: 'none', borderLeft: 'none' })}>{(+item.cgstPercent).toFixed(2)}%</td>
                <td style={cell({ textAlign: 'right', borderTop: 'none', borderLeft: 'none', fontFamily: 'Courier New, monospace' })}>{(+item.cgstAmount).toFixed(2)}</td>
                <td style={cell({ textAlign: 'center', borderTop: 'none', borderLeft: 'none' })}>{(+item.sgstPercent).toFixed(2)}%</td>
                <td style={cell({ textAlign: 'right', borderTop: 'none', borderLeft: 'none', fontFamily: 'Courier New, monospace' })}>{(+item.sgstAmount).toFixed(2)}</td>
              </>}
              {isGST && !intra && <>
                <td style={cell({ textAlign: 'center', borderTop: 'none', borderLeft: 'none' })}>{(+item.igstPercent).toFixed(2)}%</td>
                <td style={cell({ textAlign: 'right', borderTop: 'none', borderLeft: 'none', fontFamily: 'Courier New, monospace' })}>{(+item.igstAmount).toFixed(2)}</td>
              </>}
              <td style={cell({ textAlign: 'right', borderTop: 'none', borderLeft: 'none', fontWeight: 700, fontFamily: 'Courier New, monospace' })}>{(+item.totalAmount).toFixed(2)}</td>
            </tr>
          ))}
          {/* Filler rows */}
          {Array.from({ length: Math.max(0, 4 - invoice.items.length) }).map((_, i) => (
            <tr key={`fill-${i}`}>
              <td style={cell({ borderTop: 'none', height: 18 })} colSpan={cols.length}>&nbsp;</td>
            </tr>
          ))}
        </tbody>
      </table>

      {/* ── TOTALS ────────────────────────────────────────────────── */}
      <table style={{ width: '100%', borderCollapse: 'collapse', tableLayout: 'fixed', marginTop: -1 }}>
        <colgroup><col style={{ width: '56%' }} /><col style={{ width: '44%' }} /></colgroup>
        <tbody>
          <tr>
            {/* Left: words + breakdown */}
            <td style={cell({ padding: '7px 9px', verticalAlign: 'top' })}>
              <div style={{ fontWeight: 700, fontSize: 9, marginBottom: 3 }}>Invoice Value (In Words)</div>
              <div style={{ fontStyle: 'italic', fontSize: 9, lineHeight: 1.5 }}>
                Rs. {numberToWords(Math.round(invoice.grandTotal || 0))}
              </div>
              {isGST && (
                <div style={{ marginTop: 8, fontSize: 9 }}>
                  <table style={{ borderCollapse: 'collapse', fontSize: 9 }}>
                    <tbody>
                      <tr>
                        <td style={{ paddingRight: 20, paddingBottom: 2 }}>Sale @{invoice.items[0]?.gstPercent || 18}%</td>
                        <td style={{ fontFamily: 'Courier New, monospace', textAlign: 'right' }}>{(+(invoice.taxableAmount || 0)).toFixed(2)}</td>
                      </tr>
                      {intra ? <>
                        <tr>
                          <td style={{ paddingRight: 20, paddingBottom: 2 }}>CGST @{invoice.items[0]?.cgstPercent || 9}%</td>
                          <td style={{ fontFamily: 'Courier New, monospace', textAlign: 'right' }}>{(+(invoice.totalCgst || 0)).toFixed(2)}</td>
                        </tr>
                        <tr>
                          <td style={{ paddingRight: 20, paddingBottom: 2 }}>UTGST @{invoice.items[0]?.sgstPercent || 9}%</td>
                          <td style={{ fontFamily: 'Courier New, monospace', textAlign: 'right' }}>{(+(invoice.totalSgst || 0)).toFixed(2)}</td>
                        </tr>
                      </> : (
                        <tr>
                          <td style={{ paddingRight: 20 }}>IGST @{invoice.items[0]?.igstPercent || 18}%</td>
                          <td style={{ fontFamily: 'Courier New, monospace', textAlign: 'right' }}>{(+(invoice.totalIgst || 0)).toFixed(2)}</td>
                        </tr>
                      )}
                    </tbody>
                  </table>
                </div>
              )}
              {invoice.notes && (
                <div style={{ marginTop: 6, fontSize: 9 }}><strong>REMARKS:</strong> {invoice.notes}</div>
              )}
            </td>

            {/* Right: amount table */}
            <td style={cell({ padding: 0, verticalAlign: 'top' })}>
              <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 9 }}>
                <tbody>
                  {[
                    { label: 'Total',           val: (+(invoice.taxableAmount||0)).toFixed(2), bold: false },
                    isGST && intra  ? { label: 'CGST Amount',   val: (+(invoice.totalCgst||0)).toFixed(2),  bold: false } : null,
                    isGST && intra  ? { label: 'UTGST Amount',  val: (+(invoice.totalSgst||0)).toFixed(2),  bold: false } : null,
                    isGST && !intra ? { label: 'IGST Amount',   val: (+(invoice.totalIgst||0)).toFixed(2),  bold: false } : null,
                    isGST           ? { label: 'GST Amount',    val: (+(invoice.totalGst||0)).toFixed(2),   bold: false } : null,
                    { label: 'FREIGHT',          val: '0.00', bold: false },
                    { label: 'FREIGHT ON GST',   val: '0.00', bold: false },
                  ].filter(Boolean).map((row, i) => (
                    <tr key={i}>
                      <td style={{ padding: '3px 8px', borderBottom: '1px solid #ddd', fontSize: 9, color: '#333' }}>{row.label}</td>
                      <td style={{ padding: '3px 8px', borderBottom: '1px solid #ddd', textAlign: 'right', fontSize: 9, fontFamily: 'Courier New, monospace', fontWeight: row.bold ? 700 : 400 }}>{row.val}</td>
                    </tr>
                  ))}
                  {/* Grand Total */}
                  <tr style={{ background: '#e8e8e8' }}>
                    <td style={{ padding: '5px 8px', fontWeight: 900, fontSize: 11, borderTop: '2px solid #000', borderBottom: '1px solid #ddd' }}>Invoice Total</td>
                    <td style={{ padding: '5px 8px', fontWeight: 900, fontSize: 11, textAlign: 'right', fontFamily: 'Courier New, monospace', borderTop: '2px solid #000', borderBottom: '1px solid #ddd' }}>
                      Rs. {(+(invoice.grandTotal||0)).toFixed(2)}
                    </td>
                  </tr>
                  {/* Paid */}
                  <tr>
                    <td style={{ padding: '3px 8px', fontSize: 9, color: '#1a6e3c', borderBottom: '1px solid #ddd' }}>Paid Amount</td>
                    <td style={{ padding: '3px 8px', textAlign: 'right', fontFamily: 'Courier New, monospace', fontSize: 9, color: '#1a6e3c', borderBottom: '1px solid #ddd' }}>
                      {(+(invoice.paidAmount||0)).toFixed(2)}
                    </td>
                  </tr>
                  {/* Due */}
                  {(invoice.dueAmount || 0) > 0 && (
                    <tr>
                      <td style={{ padding: '3px 8px', fontSize: 9, color: '#c00', fontWeight: 700 }}>Balance Due</td>
                      <td style={{ padding: '3px 8px', textAlign: 'right', fontFamily: 'Courier New, monospace', fontSize: 9, color: '#c00', fontWeight: 700 }}>
                        {(+(invoice.dueAmount||0)).toFixed(2)}
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </td>
          </tr>
        </tbody>
      </table>

      {/* ── TERMS + SIGNATURE ─────────────────────────────────────── */}
      <table style={{ width: '100%', borderCollapse: 'collapse', tableLayout: 'fixed', marginTop: -1 }}>
        <colgroup><col style={{ width: '62%' }} /><col style={{ width: '38%' }} /></colgroup>
        <tbody>
          <tr>
            <td style={cell({ padding: '6px 9px', verticalAlign: 'top' })}>
              <div style={{ fontWeight: 700, fontSize: 9, marginBottom: 2 }}>TERM &amp; CONDITION OF SALE</div>
              <div style={{ fontSize: 8.5, color: '#444', lineHeight: 1.6 }}>
                {s.termsAndConditions || 'Interest @20% p.a. will be charged on all outstanding bills. Our responsibility ceases as soon as goods are handed over to the carrier / Railway. In case of any dispute or difference, Chandigarh courts alone will have jurisdiction.'}
              </div>
              <div style={{ marginTop: 4, fontSize: 8, color: '#666' }}>
                Certified that the Particulars given above are true and correct
              </div>
            </td>
            <td style={cell({ padding: '6px 9px', textAlign: 'center', verticalAlign: 'top', borderLeft: 'none' })}>
              <div style={{ fontSize: 9 }}>For <strong>{s.shopName}</strong></div>
              <div style={{ marginTop: 36, borderTop: '1px solid #000', paddingTop: 3, fontWeight: 700, fontSize: 9 }}>
                Authorised Signatory
              </div>
            </td>
          </tr>
        </tbody>
      </table>

      {/* ── PACKED / DISPATCHED / PREPARED ───────────────────────── */}
      <table style={{ width: '100%', borderCollapse: 'collapse', tableLayout: 'fixed', marginTop: -1 }}>
        <colgroup><col style={{ width: '33.33%' }} /><col style={{ width: '33.33%' }} /><col style={{ width: '33.34%' }} /></colgroup>
        <tbody>
          <tr>
            {['Packed By', 'Dispatched By', 'Prepared By'].map((label, i) => (
              <td key={i} style={cell({ padding: '5px 9px', borderLeft: i > 0 ? 'none' : undefined })}>
                <div style={{ fontWeight: 700, fontSize: 9 }}>{label}</div>
                <div style={{ marginTop: 14, fontSize: 8, color: '#888' }}>
                  {label === 'Dispatched By' ? 'BY HAND' : '______________________'}
                </div>
              </td>
            ))}
          </tr>
        </tbody>
      </table>

      <div style={{ textAlign: 'center', fontSize: 7.5, color: '#aaa', marginTop: 5 }}>
        Original For Consignee &nbsp;|&nbsp; Computer Generated Invoice
      </div>
    </div>
  );
});

/* ══════════════════════════════════════════════════════════════════
   PAGE COMPONENT
══════════════════════════════════════════════════════════════════ */
export default function InvoiceDetail() {
  const { id }    = useParams();
  const printRef  = useRef();
  const [invoice,  setInvoice]  = useState(null);
  const [settings, setSettings] = useState(null);
  const [loading,  setLoading]  = useState(true);
  const [showPayModal, setShowPayModal] = useState(false);
  const [payForm, setPayForm] = useState({ amount: '', method: 'cash', reference: '', note: '' });
  const [saving,  setSaving] = useState(false);

  useEffect(() => {
    Promise.all([api.get(`/invoices/${id}`), api.get('/settings')])
      .then(([inv, set]) => { setInvoice(inv.data.data); setSettings(set.data.data); })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, [id]);

  const handlePrint = useReactToPrint({
    content: () => printRef.current,
    documentTitle: invoice ? `Invoice-${invoice.invoiceNumber}` : 'Invoice',
    pageStyle: `
      @page { size: A4 portrait; margin: 6mm; }
      @media print {
        * { -webkit-print-color-adjust: exact !important; print-color-adjust: exact !important; }
        body { margin: 0; padding: 0; }
      }
    `,
  });

  const handlePayment = async () => {
    if (!payForm.amount) return;
    setSaving(true);
    try {
      await api.post(`/invoices/${id}/payment`, { ...payForm, amount: Number(payForm.amount) });
      const res = await api.get(`/invoices/${id}`);
      setInvoice(res.data.data);
      setShowPayModal(false);
      setPayForm({ amount: '', method: 'cash', reference: '', note: '' });
    } finally { setSaving(false); }
  };

  if (loading) return <Layout title="Invoice"><div className="loading"><div className="spinner" /></div></Layout>;
  if (!invoice) return <Layout title="Invoice"><div className="alert alert-danger">Invoice not found.</div></Layout>;

  const statusBadge = { paid: 'success', partial: 'warning', pending: 'danger', credit: 'info' };

  return (
    <Layout title={`Invoice — ${invoice.invoiceNumber}`}>
      {/* Action bar */}
      <div className="no-print" style={{ display: 'flex', gap: 10, marginBottom: 22, flexWrap: 'wrap', alignItems: 'center' }}>
        <Link to="/billing" className="btn btn-secondary btn-sm">&#8592; Back</Link>
        <button className="btn btn-primary" onClick={handlePrint}>Print / Download PDF</button>
        {invoice.dueAmount > 0 && (
          <button className="btn btn-success" onClick={() => setShowPayModal(true)}>Record Payment</button>
        )}
        <span className={`badge badge-${statusBadge[invoice.paymentStatus] || 'default'}`} style={{ fontSize: 12, padding: '4px 14px' }}>
          {invoice.paymentStatus?.toUpperCase()}
        </span>
        {invoice.dueAmount > 0 && (
          <span style={{ color: 'var(--danger)', fontWeight: 700, fontSize: 13 }}>Due: {formatCurrency(invoice.dueAmount)}</span>
        )}
        {invoice.paidAmount > 0 && (
          <span style={{ color: 'var(--success)', fontWeight: 600, fontSize: 13 }}>Paid: {formatCurrency(invoice.paidAmount)}</span>
        )}
      </div>

      {/* Preview */}
      <div className="card no-print" style={{ marginBottom: 20 }}>
        <div className="card-header">
          <span className="card-title">Invoice Preview — {invoice.invoiceNumber}</span>
          <span style={{ fontSize: 12, color: 'var(--text-muted)' }}>
            {formatDate(invoice.invoiceDate)} &nbsp;&mdash;&nbsp; {invoice.customerName}
          </span>
        </div>
        <div style={{ padding: 24, background: '#f0f3f8', overflowX: 'auto' }}>
          <div style={{ background: '#fff', boxShadow: '0 4px 24px rgba(0,0,0,0.12)', borderRadius: 4, display: 'inline-block', minWidth: '100%' }}>
            <InvoicePrint ref={printRef} invoice={invoice} settings={settings} />
          </div>
        </div>
      </div>

      {/* Payment history */}
      {invoice.payments?.length > 0 && (
        <div className="card no-print">
          <div className="card-header"><span className="card-title">Payment History</span></div>
          <div className="table-container">
            <table>
              <thead>
                <tr>
                  <th>#</th><th>Date</th><th>Method</th><th>Reference</th>
                  <th className="text-right">Amount</th><th>Note</th>
                </tr>
              </thead>
              <tbody>
                {invoice.payments.map((p, i) => (
                  <tr key={i}>
                    <td style={{ color: 'var(--text-muted)' }}>{i + 1}</td>
                    <td>{formatDate(p.date)}</td>
                    <td style={{ textTransform: 'capitalize' }}>{p.method}</td>
                    <td style={{ fontFamily: 'var(--font-mono)', fontSize: 12, color: 'var(--text-muted)' }}>{p.reference || '—'}</td>
                    <td className="text-right" style={{ color: 'var(--success)', fontWeight: 700, fontFamily: 'var(--font-mono)' }}>
                      {formatCurrency(p.amount)}
                    </td>
                    <td style={{ color: 'var(--text-muted)', fontSize: 12 }}>{p.note || '—'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Payment modal */}
      {showPayModal && (
        <div className="modal-overlay" onClick={() => setShowPayModal(false)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <span className="modal-title">Record Payment</span>
              <button className="btn btn-secondary btn-sm" onClick={() => setShowPayModal(false)}>Close</button>
            </div>
            <div className="modal-body">
              <div style={{ background: 'var(--danger-bg)', borderRadius: 8, padding: '12px 16px', marginBottom: 16 }}>
                <strong style={{ color: 'var(--danger)', fontSize: 14 }}>Due: {formatCurrency(invoice.dueAmount)}</strong>
              </div>
              <div className="form-row">
                <div className="form-group">
                  <label className="form-label">Amount Received</label>
                  <input className="form-control" type="number" min={0} step={0.01}
                    value={payForm.amount}
                    onChange={(e) => setPayForm((f) => ({ ...f, amount: e.target.value }))}
                    placeholder={invoice.dueAmount} autoFocus
                  />
                </div>
                <div className="form-group">
                  <label className="form-label">Method</label>
                  <select className="form-control" value={payForm.method} onChange={(e) => setPayForm((f) => ({ ...f, method: e.target.value }))}>
                    {['cash','upi','card','bank','cheque'].map((m) => <option key={m}>{m}</option>)}
                  </select>
                </div>
              </div>
              <div className="form-group">
                <label className="form-label">Reference / Transaction ID</label>
                <input className="form-control" value={payForm.reference} onChange={(e) => setPayForm((f) => ({ ...f, reference: e.target.value }))} placeholder="UPI ref, cheque no..." />
              </div>
              <div className="form-group">
                <label className="form-label">Note</label>
                <input className="form-control" value={payForm.note} onChange={(e) => setPayForm((f) => ({ ...f, note: e.target.value }))} />
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setShowPayModal(false)}>Cancel</button>
              <button className="btn btn-success" onClick={handlePayment} disabled={saving || !payForm.amount}>
                {saving ? 'Saving...' : 'Save Payment'}
              </button>
            </div>
          </div>
        </div>
      )}
    </Layout>
  );
}
